effect.shader:
void main() {
    vec2 texelSize = 1.0 / getTexSize(inputImg.size);
    //vec4 fg = texture2DCv(inputImg.texture,acScreenNorm);
    //vec4 bg = texture2DCv(comp.texture,acScreenNorm);
    //float diff = length(fg.rgb - bg.rgb) * fg.a;

    float lowCutoff = threshold-(threshold*feather);
    float hiCutoff = threshold;
    float range = hiCutoff - lowCutoff;

    float pLeft = 0.0;
    float pRight = 0.0;
    float pUp = 0.0;
    float pDown = 0.0;


    vec2 velocity;

    // ------- HORIZONTAL ---------------------------------------------------------------
    velocity = vec2(0.1,0.0) * density;
    velocity *= acPreviewSize*texelSize;
    velocity.x *= acScreenSize.y / acScreenSize.x;
    float speed = length(velocity / texelSize);
    int nSamples = int(clamp(speed, 1.01, 30.01));

    // RIGHT
    for(int i=1; i<nSamples; i++ ) {
        vec2 offset = velocity * (float(i) / float(nSamples - 1) /*- 0.5*/ );
        vec2 sampleCoord;

        sampleCoord = acScreenNorm.st+offset;
        float insideTexture = step(0.0,sampleCoord.x) * step(sampleCoord.x,1.0) * step(0.0,sampleCoord.y) * step(sampleCoord.y,1.0);
        //vec4 samp = texture2DCv(inputImg.texture, sampleCoord) * insideTexture;

        vec4 fg = texture2DCv(inputImg.texture,sampleCoord) * insideTexture;;
        vec4 bg = texture2DCv(comp.texture,sampleCoord);
        float diff = length(fg.rgb - bg.rgb) * fg.a;

        float t;
        if( sampling == 0 ) {
            t = clamp((diff - lowCutoff)/range,0.0,1.0);
        } else {
            t = smoothstep(lowCutoff,hiCutoff,diff);
        }

        pRight = max(pRight, t);

    }


    // LEFT
    for(int i=1; i<nSamples; i++ ) {
        vec2 offset = velocity * (float(i) / float(nSamples - 1) /*- 0.5*/ );
        vec2 sampleCoord;

        sampleCoord = acScreenNorm.st-offset;
        float insideTexture = step(0.0,sampleCoord.x) * step(sampleCoord.x,1.0) * step(0.0,sampleCoord.y) * step(sampleCoord.y,1.0);
        //vec4 samp = texture2DCv(inputImg.texture, sampleCoord) * insideTexture;

        vec4 fg = texture2DCv(inputImg.texture,sampleCoord) * insideTexture;;
        vec4 bg = texture2DCv(comp.texture,sampleCoord);
        float diff = length(fg.rgb - bg.rgb) * fg.a;

        float t;
        if( sampling == 0 ) {
            t = clamp((diff - lowCutoff)/range,0.0,1.0);
        } else {
            t = smoothstep(lowCutoff,hiCutoff,diff);
        }

        pLeft = max(pLeft, t);

    }

    // ------- VERTICAL ---------------------------------------------------------------
    velocity = vec2(0.0,0.1) * density;
    velocity *= acPreviewSize * texelSize;
    velocity.x *= acScreenSize.y / acScreenSize.x;
    speed = length(velocity / texelSize);
    nSamples = int(clamp(speed, 1.01, 30.01));

    // UP
    for(int i=1; i<nSamples; i++ ) {
        vec2 offset = velocity * (float(i) / float(nSamples - 1) /*- 0.5*/ );
        vec2 sampleCoord;

        sampleCoord = acScreenNorm.st+offset;
        float insideTexture = step(0.0,sampleCoord.x) * step(sampleCoord.x,1.0) * step(0.0,sampleCoord.y) * step(sampleCoord.y,1.0);
        //vec4 samp = texture2DCv(inputImg.texture, sampleCoord) * insideTexture;

        vec4 fg = texture2DCv(inputImg.texture,sampleCoord) * insideTexture;;
        vec4 bg = texture2DCv(comp.texture,sampleCoord);
        float diff = length(fg.rgb - bg.rgb) * fg.a;

        float t;
        if( sampling == 0 ) {
            t = clamp((diff - lowCutoff)/range,0.0,1.0);
        } else {
            t = smoothstep(lowCutoff,hiCutoff,diff);
        }

        pUp = max(pUp, t);

    }


    // DOWN
    for(int i=1; i<nSamples; i++ ) {
        vec2 offset = velocity * (float(i) / float(nSamples - 1) /*- 0.5*/ );
        vec2 sampleCoord;

        sampleCoord = acScreenNorm.st-offset;
        float insideTexture = step(0.0,sampleCoord.x) * step(sampleCoord.x,1.0) * step(0.0,sampleCoord.y) * step(sampleCoord.y,1.0);
        //vec4 samp = texture2DCv(inputImg.texture, sampleCoord) * insideTexture;

        vec4 fg = texture2DCv(inputImg.texture,sampleCoord) * insideTexture;;
        vec4 bg = texture2DCv(comp.texture,sampleCoord);
        float diff = length(fg.rgb - bg.rgb) * fg.a;

        float t;
        if( sampling == 0 ) {
            t = clamp((diff - lowCutoff)/range,0.0,1.0);
        } else {
            t = smoothstep(lowCutoff,hiCutoff,diff);
        }

        pDown = max(pDown, t);

    }

    float p = max(min(pLeft,pRight), min(pUp,pDown));

    vec4 fg = texture2DCv(inputImg.texture,acScreenNorm);
    if( density < 0.0001 ) {
        vec4 bg = texture2DCv(comp.texture,acScreenNorm);
        float diff = length(fg.rgb - bg.rgb) * fg.a;
        if( sampling == 0 ) {
            p = clamp((diff - lowCutoff)/range,0.0,1.0);
        } else {
            p = smoothstep(lowCutoff,hiCutoff,diff);
        }
    }

    if( p < offset ) p = 0.0;

    if( mode==0 ) {
        gl_FragColor = fg * p;
    } else if( mode==1 ) {
        gl_FragColor = vec4(p,p,p,1.0) * fg.a;
    } else if( mode==2 ) {
        gl_FragColor = vec4(pLeft,pUp,pRight,1.0) * fg.a;
    } else {
        gl_FragColor = vec4(p,p,p,1.0) * fg.a;
    }
}

    //float p = smoothstep(threshold-(threshold*feather),threshold,diff);
